# Provider-Specific Model Settings

Configuration patterns for provider-specific features like OpenAI reasoning models and Anthropic extended thinking.

## OpenAI Reasoning Models

For models like `o1`, `o3`, and `o3-mini` that support extended reasoning:

### Python
```python
agent = client.agents.create(
    model="openai/o3-mini",
    model_settings={
        "provider_type": "openai",
        "reasoning": {
            "reasoning_effort": "medium"  # "low", "medium", or "high"
        }
    }
)
```

### TypeScript
```typescript
const agent = await client.agents.create({
  model: "openai/o3-mini",
  model_settings: {
    provider_type: "openai",
    reasoning: {
      reasoning_effort: "medium",  // "low", "medium", or "high"
    },
  },
});
```

### Reasoning Effort Levels

| Level | Use Case | Cost |
|-------|----------|------|
| `low` | Simple tasks, faster responses | Lower |
| `medium` | Balanced reasoning (recommended default) | Medium |
| `high` | Complex multi-step reasoning | Higher |

## Anthropic Extended Thinking

For Claude models with extended thinking capability:

### Python
```python
agent = client.agents.create(
    model="anthropic/claude-sonnet-4-5-20250929",
    model_settings={
        "provider_type": "anthropic",
        "thinking": {
            "type": "enabled",
            "budget_tokens": 10000
        }
    }
)
```

### TypeScript
```typescript
const agent = await client.agents.create({
  model: "anthropic/claude-sonnet-4-5-20250929",
  model_settings: {
    provider_type: "anthropic",
    thinking: {
      type: "enabled",
      budget_tokens: 10000,
    },
  },
});
```

### Thinking Budget

The `budget_tokens` parameter controls how many tokens Claude can use for internal reasoning before responding:

| Budget | Use Case |
|--------|----------|
| 5000 | Quick reasoning tasks |
| 10000 | Standard complex tasks (recommended) |
| 20000+ | Very complex multi-step problems |

**Note:** Higher budgets increase latency and cost but can improve quality on complex tasks.

## Combining Settings

You can combine provider-specific settings with standard settings:

```python
agent = client.agents.create(
    model="openai/o3-mini",
    model_settings={
        "provider_type": "openai",
        "temperature": 0.7,
        "max_output_tokens": 4096,
        "reasoning": {
            "reasoning_effort": "high"
        }
    },
    context_window_limit=128000
)
```

## Common Mistakes

**Wrong: Missing provider_type**
```python
# Bad - missing required provider_type field
model_settings={
    "temperature": 0.7  # Missing provider_type!
}
```

**Correct: Include provider_type**
```python
# Good - provider_type included
model_settings={
    "provider_type": "openai",
    "temperature": 0.7
}
```

**Wrong: Reasoning settings at top level**
```python
# Bad - reasoning_effort not recognized at top level
model_settings={
    "provider_type": "openai",
    "reasoning_effort": "medium"  # Wrong!
}
```

**Correct: Nested under "reasoning" key**
```python
# Good - properly nested
model_settings={
    "provider_type": "openai",
    "reasoning": {
        "reasoning_effort": "medium"
    }
}
```

**Wrong: Thinking settings without type**
```python
# Bad - missing required "type" field
model_settings={
    "provider_type": "anthropic",
    "thinking": {
        "budget_tokens": 10000  # Missing type!
    }
}
```

**Correct: Include type field**
```python
# Good - type field included
model_settings={
    "provider_type": "anthropic",
    "thinking": {
        "type": "enabled",
        "budget_tokens": 10000
    }
}
```

#!/usr/bin/env npx ts-node
/**
 * Basic Model Configuration Example (TypeScript)
 *
 * Demonstrates how to create a Letta agent with custom model settings.
 *
 * Usage:
 *     export LETTA_API_KEY="your-api-key"
 *     npx ts-node basic_config.ts
 */

import Letta from "@letta-ai/letta-client";

async function main() {
  // Initialize client
  const client = new Letta({ apiKey: process.env.LETTA_API_KEY });

  // Create agent with model configuration
  const agent = await client.agents.create({
    name: "configured-agent-ts",
    // Model handle format: provider/model-name
    model: "openai/gpt-4o",
    // Model behavior settings (provider_type required!)
    model_settings: {
      provider_type: "openai", // Must match model provider
      temperature: 0.7, // 0.0-2.0, lower = more deterministic
      max_output_tokens: 4096, // Maximum response length
    },
    // Context window (set at agent level, not in model_settings)
    context_window_limit: 128000,
    // Memory blocks
    memory_blocks: [
      { label: "persona", value: "You are a helpful assistant." },
      { label: "human", value: "The user hasn't shared any information yet." },
    ],
  });

  console.log(`Created agent: ${agent.id}`);
  console.log(`Model: ${agent.model}`);

  // Send a test message
  const response = await client.agents.messages.create(agent.id, {
    messages: [{ role: "user", content: "Hello! What model are you running on?" }],
  });

  // Print response
  for (const message of response.messages) {
    if ("content" in message && message.content) {
      console.log(`Agent: ${message.content}`);
    }
  }
}

main().catch(console.error);

#!/usr/bin/env python3
"""
Provider-Specific Settings Example

Demonstrates how to configure OpenAI reasoning models and
Anthropic extended thinking capabilities.

Usage:
    export LETTA_API_KEY="your-api-key"
    python provider_specific.py
"""

import os
from letta_client import Letta

# Initialize client
client = Letta(api_key=os.getenv("LETTA_API_KEY"))

# ============================================================
# OpenAI Reasoning Models (o1, o3, o3-mini)
# ============================================================

print("=== OpenAI Reasoning Model ===")

reasoning_agent = client.agents.create(
    name="reasoning-demo",
    model="openai/o3-mini",
    model_settings={
        "provider_type": "openai",  # Required field
        # Reasoning settings must be nested under "reasoning" key
        "reasoning": {
            "reasoning_effort": "medium"  # "low", "medium", or "high"
        }
    },
    memory_blocks=[
        {"label": "persona", "value": "You are a logical problem solver."},
        {"label": "human", "value": ""}
    ]
)

print(f"Created reasoning agent: {reasoning_agent.id}")

# Test with a reasoning task
response = client.agents.messages.create(
    agent_id=reasoning_agent.id,
    messages=[{
        "role": "user",
        "content": "If all cats are mammals, and some mammals are black, can we conclude that some cats are black?"
    }]
)

for message in response.messages:
    if hasattr(message, "content") and message.content:
        print(f"Reasoning agent: {message.content}")

# ============================================================
# Anthropic Extended Thinking
# ============================================================

print("\n=== Anthropic Extended Thinking ===")

thinking_agent = client.agents.create(
    name="thinking-demo",
    model="anthropic/claude-sonnet-4-5-20250929",
    model_settings={
        "provider_type": "anthropic",  # Required field
        # Thinking settings must be nested under "thinking" key
        "thinking": {
            "type": "enabled",     # Required field
            "budget_tokens": 10000  # How many tokens for internal reasoning
        }
    },
    memory_blocks=[
        {"label": "persona", "value": "You are a thoughtful analyst."},
        {"label": "human", "value": ""}
    ]
)

print(f"Created thinking agent: {thinking_agent.id}")

# Test with a complex task
response = client.agents.messages.create(
    agent_id=thinking_agent.id,
    messages=[{
        "role": "user",
        "content": "What are three non-obvious implications of widespread AI adoption in healthcare?"
    }]
)

for message in response.messages:
    if hasattr(message, "content") and message.content:
        print(f"Thinking agent: {message.content}")

# ============================================================
# Combined Settings
# ============================================================

print("\n=== Combined Settings ===")

# You can combine provider-specific settings with standard settings
combined_agent = client.agents.create(
    name="combined-demo",
    model="openai/o3-mini",
    model_settings={
        "provider_type": "openai",  # Required field
        "temperature": 0.7,
        "max_output_tokens": 4096,
        "reasoning": {
            "reasoning_effort": "high"
        }
    },
    context_window_limit=128000,
    memory_blocks=[
        {"label": "persona", "value": "You solve complex problems step by step."},
        {"label": "human", "value": ""}
    ]
)

print(f"Created combined agent: {combined_agent.id}")
print("Agent configured with temperature, max_output_tokens, and reasoning_effort")

